import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.scaladsl.Source

import scala.concurrent.Future

object WebhookProxy {
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("WebhookProxy")
    implicit val executionContext = system.dispatcher

    val route =
      path("forward") {
        post {
          entity(as[Map[String, String]]) { userUrls =>
            val requests = for ((url, _) <- userUrls) yield HttpRequest(uri = uri"$url")
            val futures: Iterable[Future[HttpResponse]] = requests.map(Http().singleRequest(_))
            val combinedSource: Source[HttpResponse, Any] = Source.fromIterable(futures)
            complete(combinedSource.flatMapMerge(identity).map(_.entity.asString()))
          }
        }
      }

    val bindingFuture = Http().bindAndHandle(route, interface = "localhost", port = 8080)

    println(s"Server online at http://${bindingFuture.localAddress}/**")
  }
}